#include<bits/stdc++.h>
using namespace std;
double f[205][205],mp[205][205],max1[205],colmax1[205];
int n,m,x[205],y[205];
double dist(int i,int j)
{
    return sqrt(pow((x[i]-x[j]),2)+pow((y[i]-y[j]),2));
}
int col[205];
void dfs(int x,int c)
{
    col[x]=c;
    for(int i=1;i<=n;i++)
    {
        if(!col[i]&&mp[x][i]<1e9)
        {
            dfs(i,c);
        }
    }
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            f[i][j]=mp[i][j]=1e10;
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            char ch;
            cin>>ch;
            if(ch=='1')
            {
                int a=i,b=j;
                mp[a][b]=mp[b][a]=f[a][b]=f[b][a]=dist(a,b);
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        f[i][i]=0;
    }
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
            }
        }
    }
    int tot=0;
    for(int i=1;i<=n;i++)
    {
        if(!col[i])
        {
            dfs(i,++tot);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(f[i][j]>1e9)
            {
                continue;
            }
            max1[i]=max(max1[i],f[i][j]);
        }
        colmax1[col[i]]=max(colmax1[col[i]],max1[i]);
    }
    double ans=1e10;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)if(col[i]!=col[j])
        {
            ans=min(ans,max({colmax1[col[i]],colmax1[col[j]],max1[i]+dist(i,j)+max1[j]}));
        }
    }
    printf("%.6lf",ans);
    return 0;
}
